// ── Helper functions ──────────────────────────────────────────────────────────

func ptInitialDrawer(vm PaymentTermsVM) string {
	open := "false"
	if vm.DrawerOpen {
		open = "true"
	}
	return fmt.Sprintf(`{ drawerOpen: %s }`, open)
}

func ptDiscountData(vm PaymentTermsVM) string {
	pct := vm.DiscountPct
	if pct == "" {
		pct = "0"
	}
	return fmt.Sprintf(`{ discountPct: %q }`, pct)
}

func ptRowClass(pt models.PaymentTerm) string {
	if !pt.IsActive {
		return "border-b border-border-subtle bg-background text-text-muted2"
	}
	return "border-b border-border-subtle"
}

func ptDiscountDisplay(pt models.PaymentTerm) string {
	if pt.DiscountPct.IsZero() {
		return "—"
	}
	pct := pt.DiscountPct.StringFixed(2)
	// Trim trailing zeros.
	for len(pct) > 0 && pct[len(pct)-1] == '0' {
		pct = pct[:len(pct)-1]
	}
	if len(pct) > 0 && pct[len(pct)-1] == '.' {
		pct = pct[:len(pct)-1]
	}
	return fmt.Sprintf("%s%% / %d days", pct, pt.DiscountDays)
}

func ptInputClass(hasErr bool) string {
	return "mt-2 " + ptInputClassRaw(hasErr)
}

func ptInputClassRaw(hasErr bool) string {
	base := "block w-full rounded-md border px-3 py-2 text-body outline-none focus:ring-2 "
	if hasErr {
		return base + "border-danger focus:ring-danger-focus"
	}
	return base + "border-border-input focus:ring-primary-focus"
}

